1	// depth_lidar_fusion_node.cpp
2	//
3	// Faithful C++ port of guide_mate_explorer/depth_lidar_fusion.py. Folds OAK-D
4	// depth obstacles into the lidar scan and republishes a fused LaserScan
5	// (range = min(lidar, depth) per beam) on `scan_out`. See the Python node's
6	// module docstring for the full algorithm rationale; this port mirrors its
7	// numerics -- including numpy's float32 precision on the decision-critical path
8	// (height bands, projection, beam binning) -- so the fused scan is behaviourally
9	// equivalent while costing far less CPU (no per-message Python TF/image
10	// deserialization).
11	//
12	// Pipeline: data-driven ground-line fit -> per-column vertical collapse (keep
13	// nearest pixel inside the height band, drop the floor) -> optional drop-edge
14	// detection -> back-project + static extrinsic into the lidar frame -> bin onto
15	// the beam grid (min) -> inject only where depth is NEARER than the lidar.
16	//
17	// Namespaced TF: the TransformListener subscribes to the GLOBAL /tf, so launch
18	// with ('/tf','tf'),('/tf_static','tf_static') remaps or lookups fail silently.
19	#include <algorithm>
20	#include <cmath>
21	#include <limits>
22	#include <memory>
23	#include <string>
