57	// Least-squares fit y = A*x + B. Returns false if < 2 points.
58	bool polyfit1(const std::vector<double> & x, const std::vector<double> & y,
59	  double & A, double & B)
60	{
61	  const size_t n = x.size();
62	  if (n < 2) {
63	    return false;
64	  }
65	  double sx = 0.0, sy = 0.0, sxx = 0.0, sxy = 0.0;
66	  for (size_t i = 0; i < n; ++i) {
67	    sx += x[i];
68	    sy += y[i];
69	    sxx += x[i] * x[i];
70	    sxy += x[i] * y[i];
71	  }
72	  const double dn = static_cast<double>(n);
73	  const double denom = dn * sxx - sx * sx;
74	  if (std::abs(denom) < 1e-12) {
75	    return false;
76	  }
77	  A = (dn * sxy - sx * sy) / denom;
78	  B = (sy - A * sx) / dn;
79	  return true;
80	}
81	
82	struct LineFit
83	{
84	  bool ok = false;
85	  double A = 0.0;
86	  double B = 0.0;
87	  int ninl = 0;
88	};
89	
90	// Robust line fit y = A*x + B: least squares + 2x MAD outlier rejection.
91	// Mirrors DepthLidarFusion._robust_line.
92	LineFit robust_line(const std::vector<double> & x, const std::vector<double> & y)
93	{
94	  LineFit out;
95	  const size_t n = x.size();
96	  if (n < 2) {
97	    return out;
98	  }
99	  double A = 0.0, B = 0.0;
100	  if (!polyfit1(x, y, A, B)) {
101	    return out;
102	  }
103	  std::vector<bool> inl(n, true);
104	  int ninl = static_cast<int>(n);
105	  for (int it = 0; it < 2; ++it) {
106	    std::vector<double> r(n);
107	    for (size_t i = 0; i < n; ++i) {
108	      r[i] = y[i] - (A * x[i] + B);
109	    }
110	    std::vector<double> rc = r;
111	    const double med = median_inplace(rc);
112	    std::vector<double> ad(n);
113	    for (size_t i = 0; i < n; ++i) {
114	      ad[i] = std::abs(r[i] - med);
115	    }
116	    std::vector<double> adc = ad;
117	    const double mad = median_inplace(adc) + 1e-6;
118	    const double thr = 3.0 * 1.4826 * mad;
119	    int cnt = 0;
120	    for (size_t i = 0; i < n; ++i) {
121	      inl[i] = ad[i] < thr;
122	      if (inl[i]) {
123	        ++cnt;
124	      }
125	    }
126	    ninl = cnt;
127	    if (cnt < 2) {
128	      break;
129	    }
130	    std::vector<double> xi, yi;
131	    xi.reserve(cnt);
132	    yi.reserve(cnt);
133	    for (size_t i = 0; i < n; ++i) {
134	      if (inl[i]) {
135	        xi.push_back(x[i]);
136	        yi.push_back(y[i]);
137	      }
138	    }
139	    if (!polyfit1(xi, yi, A, B)) {
140	      // degenerate (collinear-in-x) inliers: mirror numpy.polyfit's lstsq
141	      // result (slope 0, intercept = mean) instead of retaining the old fit.
142	      double sy = 0.0;
143	      for (double yv : yi) {
144	        sy += yv;
145	      }
146	      A = 0.0;
147	      B = sy / static_cast<double>(yi.size());
148	    }
149	  }
150	  out.ok = true;
151	  out.A = A;
152	  out.B = B;
153	  out.ninl = ninl;
154	  return out;
155	}
