235	private:
236	  static double deg2rad(double d) {return d * M_PI / 180.0;}
237	
238	  // ------------------------------------------------------------------ info
239	  void infoCb(const sensor_msgs::msg::CameraInfo::SharedPtr msg)
240	  {
241	    const auto & k = msg->k;  // row-major 3x3
242	    if (k[0] > 0.0 && k[4] > 0.0) {
243	      ci_w_ = static_cast<int>(msg->width);
244	      ci_h_ = static_cast<int>(msg->height);
245	      ci_fx_ = k[0]; ci_fy_ = k[4]; ci_cx_ = k[2]; ci_cy_ = k[5];
246	      have_ci_ = true;
247	    }
248	  }
249	
250	  // Pick intrinsics for a w x h depth image (priority: params > matching
251	  // camera_info > FOV pinhole). Mirrors _resolve_intrinsics.
252	  void resolveIntrinsics(int w, int h, double & fx, double & fy, double & cx, double & cy)
253	  {
254	    std::string src;
255	    if (param_fx_ > 0.0 && param_fy_ > 0.0) {
256	      src = "params";
257	      fx = param_fx_; fy = param_fy_; cx = param_cx_; cy = param_cy_;
258	    } else if (have_ci_ && ci_w_ == w && ci_h_ == h) {
259	      src = "camera_info";
260	      fx = ci_fx_; fy = ci_fy_; cx = ci_cx_; cy = ci_cy_;
261	    } else {
262	      src = "fov";
263	      cx = w / 2.0; cy = h / 2.0;
264	      fx = (w / 2.0) / std::tan(hfov_ / 2.0);
265	      fy = (h / 2.0) / std::tan(vfov_ / 2.0);
266	    }
267	    if (intr_src_ != src) {
268	      RCLCPP_INFO(
269	        get_logger(), "intrinsics source=%s: fx=%.1f fy=%.1f cx=%.1f cy=%.1f for depth %dx%d.",
270	        src.c_str(), fx, fy, cx, cy, w, h);
271	      if (src == "fov" && have_ci_) {
272	        RCLCPP_WARN(
273	          get_logger(), "camera_info %dx%d != depth %dx%d; using FOV model (hfov=%.0f vfov=%.0f deg).",
274	          ci_w_, ci_h_, w, h, hfov_ * 180.0 / M_PI, vfov_ * 180.0 / M_PI);
275	      }
276	      intr_src_ = src;
277	    }
278	  }
279	
280	  // ---------------------------------------------------------------- ground
281	  // Estimate the floor line v = A*(1/z) + B from this frame (A = h_cam*fy,
282	  // B ~= cy). Per-row median inverse depth -> robust line -> EMA -> coast ->
283	  // assumed-model fallback. Mirrors _ground_plane. z is row-major h*w (metres).
284	  void groundPlane(const std::vector<float> & z, int h, int w, double fy, double cy,
285	    double & outA, double & outB)
286	  {
287	    const double A0 = camera_height_ * fy;
288	    const double B0 = cy;
289	    if (!ground_estimation_) {
290	      outA = A0; outB = B0;
291	      return;
292	    }
293	    const int rows = h;
294	    int v0 = static_cast<int>(cy) + ground_row_margin_;
295	    v0 = std::max(0, std::min(v0, rows - 2));
296	
297	    // candidate rows: >= ground_min_row_px valid pixels in [range_min, ground_max_range)
298	    std::vector<int> idx;          // absolute row indices (v0..rows-1)
299	    std::vector<double> xx;        // per-row median(1/z)
300	    for (int v = v0; v < rows; ++v) {
301	      const float * row = &z[static_cast<size_t>(v) * w];
302	      std::vector<double> inv;
303	      inv.reserve(w);
304	      for (int u = 0; u < w; ++u) {
305	        const float zz = row[u];
306	        if (zz > range_min_ && zz < ground_max_range_) {
307	          inv.push_back(static_cast<double>(1.0f / zz));  // float32 reciprocal (numpy)
308	        }
309	      }
310	      if (static_cast<int>(inv.size()) >= ground_min_row_px_) {
311	        double m = median_inplace(inv);
312	        m = static_cast<double>(static_cast<float>(m));   // float32 median (numpy nanmedian)
313	        if (std::isfinite(m)) {
314	          idx.push_back(v);
315	          xx.push_back(m);
316	        }
317	      }
318	    }
319	
320	    bool good = false;
321	    LineFit lf;
322	    if (static_cast<int>(idx.size()) >= ground_min_rows_) {
323	      std::vector<double> yy(idx.size());
324	      for (size_t i = 0; i < idx.size(); ++i) {
325	        yy[i] = static_cast<double>(idx[i]);
326	      }
327	      lf = robust_line(xx, yy);
328	      good = lf.ok &&
329	        (lf.ninl >= ground_min_rows_ * 0.5) &&   // float threshold, matches Python (no int trunc)
330	        (ground_h_lo_ * fy < lf.A) && (lf.A < ground_h_hi_ * fy);
331	    }
332	
333	    if (good) {
334	      if (!have_ground_) {
335	        ground_A_ = lf.A; ground_B_ = lf.B; have_ground_ = true;
336	      } else {
337	        const double a = ground_ema_;
338	        ground_A_ = (1.0 - a) * ground_A_ + a * lf.A;
339	        ground_B_ = (1.0 - a) * ground_B_ + a * lf.B;
340	      }
341	      ground_fail_ = 0;
342	      if (ground_src_ != "fit") {
343	        RCLCPP_INFO(
344	          get_logger(), "ground: data-driven fit ON (h_cam~%.3f m, B~%.0f px)",
345	          ground_A_ / fy, ground_B_);
346	        ground_src_ = "fit";
347	      }
348	      outA = ground_A_; outB = ground_B_;
349	      return;
350	    }
351	    // fit failed this frame: coast on last good, else fall back to assumed model
352	    ++ground_fail_;
353	    if (have_ground_ && ground_fail_ <= ground_fail_max_) {
354	      outA = ground_A_; outB = ground_B_;
355	      return;
356	    }
357	    if (ground_src_ != "assumed") {
358	      RCLCPP_WARN(
359	        get_logger(), "ground: floor not reliably visible -> assumed model (h_cam=%.3f, cy=%.0f)",
360	        camera_height_, cy);
361	      ground_src_ = "assumed";
362	    }
363	    outA = A0; outB = B0;
364	  }
365	
366	  // Detect ledge/stair edges where the expected floor returns nothing. Appends
367	  // (u,v,z) edge points to the out vectors. Mirrors _drop_edges. `valid` is the
368	  // per-pixel (z>range_min && z<range_max) mask, row-major h*w.
369	  void dropEdges(const std::vector<float> & z, const std::vector<uint8_t> & valid,
370	    int h, int w, double A, double B,
371	    std::vector<float> & out_u, std::vector<float> & out_v, std::vector<float> & out_z)
372	  {
373	    std::vector<uint8_t> seen(w, 0), done(w, 0);
374	    std::vector<int> miss(w, 0), lastv(w, -1), edge(w, -1);
375	    const double gap = drop_gap_;
376	    for (int v = h - 1; v >= 1; --v) {
377	      const double denom = static_cast<double>(v) - B;
378	      if (denom <= 1.0) {       // at/above the floor horizon
379	        break;
380	      }
381	      const double zexp = A / denom;
382	      if (zexp <= range_min_) {
383	        continue;
384	      }
385	      if (zexp >= drop_check_range_) {  // past the drop horizon (only farther up)
386	        break;
387	      }
388	      const double tol = drop_floor_tol_abs_ + drop_floor_tol_rel_ * zexp;
389	      const float * row = &z[static_cast<size_t>(v) * w];
390	      const uint8_t * vrow = &valid[static_cast<size_t>(v) * w];
391	      for (int u = 0; u < w; ++u) {
392	        if (done[u]) {
393	          continue;
394	        }
395	        const bool vok = vrow[u] != 0;
396	        const float rv = row[u];
397	        const bool present = vok && (std::abs(rv - zexp) <= tol);
398	        const bool nearer = vok && (rv < zexp - tol);
399	        const bool missing = (!vok) || (vok && (rv > zexp + tol + gap));
400	        if (nearer) {           // occluder in front of floor ends the search
401	          done[u] = 1;
402	          continue;
403	        }
404	        // active (== !done) is implied here
405	        if (present) {
406	          miss[u] = 0;
407	          lastv[u] = v;
408	          seen[u] = 1;
409	        } else if (missing && seen[u]) {
410	          ++miss[u];
411	          if (miss[u] >= drop_min_missing_rows_ && lastv[u] >= 0) {
412	            edge[u] = lastv[u];
413	            done[u] = 1;
414	          }
415	        }
416	      }
417	    }
418	    for (int u = 0; u < w; ++u) {
419	      if (edge[u] >= 0) {
420	        const double dv = static_cast<double>(edge[u]);
421	        const double dz = A / (dv - B);
422	        out_u.push_back(static_cast<float>(u));
423	        out_v.push_back(static_cast<float>(dv));
424	        out_z.push_back(static_cast<float>(dz));
425	      }
426	    }
427	  }
428	
429	  // ---------------------------------------------------------------- extrinsics
430	  bool ensureExtrinsics()
431	  {
432	    if (have_extr_) {
433	      return true;
434	    }
435	    if (optical_frame_.empty() || scan_frame_.empty()) {
436	      return false;
437	    }
438	    geometry_msgs::msg::TransformStamped tf;
439	    try {
440	      tf = tf_buffer_->lookupTransform(
441	        scan_frame_, optical_frame_, tf2::TimePointZero,
442	        tf2::durationFromSec(transform_tolerance_));
443	    } catch (const tf2::TransformException & e) {
444	      if (!warned_no_tf_) {
445	        RCLCPP_WARN(get_logger(), "waiting for TF %s<-%s: %s",
446	          scan_frame_.c_str(), optical_frame_.c_str(), e.what());
447	        warned_no_tf_ = true;
448	      }
449	      return false;
450	    }
451	    const auto & q = tf.transform.rotation;
452	    const double x = q.x, y = q.y, zq = q.z, w = q.w;
453	    R_[0][0] = 1 - 2 * (y * y + zq * zq); R_[0][1] = 2 * (x * y - zq * w);     R_[0][2] = 2 * (x * zq + y * w);
454	    R_[1][0] = 2 * (x * y + zq * w);      R_[1][1] = 1 - 2 * (x * x + zq * zq); R_[1][2] = 2 * (y * zq - x * w);
455	    R_[2][0] = 2 * (x * zq - y * w);      R_[2][1] = 2 * (y * zq + x * w);      R_[2][2] = 1 - 2 * (x * x + y * y);
456	    t_[0] = tf.transform.translation.x;
457	    t_[1] = tf.transform.translation.y;
458	    t_[2] = tf.transform.translation.z;
459	    have_extr_ = true;
460	    RCLCPP_INFO(get_logger(), "extrinsics %s<-%s cached (t=[%.3f,%.3f,%.3f]).",
461	      scan_frame_.c_str(), optical_frame_.c_str(), t_[0], t_[1], t_[2]);
462	    return true;
463	  }
464	
465	  // ----------------------------------------------------------------- depth
466	  void depthCb(const sensor_msgs::msg::Image::SharedPtr msg)
467	  {
468	    optical_frame_ = msg->header.frame_id;
469	    if (!ensureExtrinsics()) {
470	      return;
471	    }
472	    const int w = static_cast<int>(msg->width);
473	    const int h = static_cast<int>(msg->height);
474	    if (w <= 0 || h <= 0) {
475	      return;
476	    }
477	    double fx, fy, cx, cy;
478	    resolveIntrinsics(w, h, fx, fy, cx, cy);
479	
480	    // 16UC1 millimetres -> metres. Row stride = msg->step bytes; take first w cols.
481	    const size_t step = msg->step;
482	    std::vector<float> z(static_cast<size_t>(h) * w);
483	    const uint8_t * data = msg->data.data();
484	    const bool swap = msg->is_bigendian != 0;
485	    for (int v = 0; v < h; ++v) {
486	      const uint8_t * rp = data + static_cast<size_t>(v) * step;
487	      float * zr = &z[static_cast<size_t>(v) * w];
488	      for (int u = 0; u < w; ++u) {
489	        uint16_t mm = static_cast<uint16_t>(rp[2 * u]) |
490	          (static_cast<uint16_t>(rp[2 * u + 1]) << 8);
491	        if (swap) {
492	          mm = static_cast<uint16_t>((mm >> 8) | (mm << 8));
493	        }
494	        zr[u] = mm * 0.001f;
495	      }
496	    }
497	
498	    double A, B;
499	    groundPlane(z, h, w, fy, cy, A, B);
500	
501	    // height above the FITTED floor = (A + (B - v)*z)/fy
502	    // keep/valid masks; per-column vertical collapse (nearest kept pixel).
503	    // float32 band constants (mirror numpy's float32 height arithmetic)
504	    const float Af = static_cast<float>(A), Bf = static_cast<float>(B);
505	    const float fyf = static_cast<float>(fy);
506	    const float minhf = static_cast<float>(min_h_), maxhf = static_cast<float>(max_h_);
507	    const float negdropf = static_cast<float>(drop_max_depth_);
508	    std::vector<uint8_t> valid(static_cast<size_t>(h) * w, 0);
509	    std::vector<float> col_min(w, kInf);
510	    std::vector<int> col_row(w, -1);
511	    for (int v = 0; v < h; ++v) {
512	      const float * zr = &z[static_cast<size_t>(v) * w];
513	      uint8_t * vr = &valid[static_cast<size_t>(v) * w];
514	      const float vf = static_cast<float>(v);
515	      for (int u = 0; u < w; ++u) {
516	        const float zz = zr[u];
517	        const bool vv = (zz > range_min_) && (zz < range_max_);
518	        vr[u] = vv ? 1 : 0;
519	        // height above the fitted floor, in float32 to match numpy: (A+(B-v)*z)/fy
520	        const float height = ((Bf - vf) * zz + Af) / fyf;
521	        const bool pos = (height > minhf) && (height < maxhf);
522	        bool keep;
523	        if (drop_detection_) {
524	          const bool neg = (height < -minhf) && (height > -negdropf);
525	          keep = vv && (pos || neg);
526	        } else {
527	          keep = vv && pos;
528	        }
529	        if (keep && zz < col_min[u]) {   // strict < => first row wins ties (argmin)
530	          col_min[u] = zz;
531	          col_row[u] = v;
532	        }
533	      }
534	    }
535	
536	    // surviving collapse points
537	    std::vector<float> uc, vc, zc;
538	    uc.reserve(w);
539	    vc.reserve(w);
540	    zc.reserve(w);
541	    for (int u = 0; u < w; ++u) {
542	      if (std::isfinite(col_min[u]) && col_row[u] >= 0) {
543	        uc.push_back(static_cast<float>(u));
544	        vc.push_back(static_cast<float>(col_row[u]));
545	        zc.push_back(col_min[u]);
546	      }
547	    }
548	
549	    // drops: append the near edges of ledges
550	    if (drop_detection_) {
551	      dropEdges(z, valid, h, w, A, B, uc, vc, zc);
552	    }
553	
554	    if (uc.empty()) {
555	      have_depth_ = false;
556	      return;
557	    }
558	
559	    // back-project to optical frame, then static extrinsic into the lidar frame
560	    // (only x,y matter for a planar scan); store range/bearing of each point.
561	    const float cxf = static_cast<float>(cx), cyf = static_cast<float>(cy);
562	    const float fxf = static_cast<float>(fx);   // fyf already in scope from the collapse loop
563	    std::vector<float> rng(uc.size()), brg(uc.size());
564	    for (size_t i = 0; i < uc.size(); ++i) {
565	      // float32 throughout to mirror numpy (R_/t_ are float; zc/uc/vc float)
566	      const float zi = zc[i];
567	      const float xo = (uc[i] - cxf) * zi / fxf;
568	      const float yo = (vc[i] - cyf) * zi / fyf;
569	      const float xl = R_[0][0] * xo + R_[0][1] * yo + R_[0][2] * zi + t_[0];
570	      const float yl = R_[1][0] * xo + R_[1][1] * yo + R_[1][2] * zi + t_[1];
571	      rng[i] = std::hypot(xl, yl);
572	      brg[i] = std::atan2(yl, xl);
573	    }
574	    depth_rng_ = std::move(rng);
575	    depth_brg_ = std::move(brg);
576	    depth_stamp_ = rclcpp::Time(msg->header.stamp);
577	    have_depth_ = true;
578	  }
