580	  // ------------------------------------------------------------------ scan
581	  void scanCb(const sensor_msgs::msg::LaserScan::SharedPtr msg)
582	  {
583	    scan_frame_ = msg->header.frame_id;
584	    const size_t n = msg->ranges.size();
585	    std::vector<float> fused(msg->ranges.begin(), msg->ranges.end());
586	
587	    std::vector<float> dmin;
588	    const bool have = depthProfile(*msg, n, dmin);
589	    if (have) {
590	      for (size_t i = 0; i < n; ++i) {
591	        float lid = fused[i];
592	        if (!std::isfinite(lid) || lid <= msg->range_min) {
593	          lid = kInf;   // lidar no-return -> empty beam
594	        }
595	        // depth overrides only when nearer than the lidar (by >= margin) or empty beam
596	        if (dmin[i] < lid - static_cast<float>(lidar_trust_margin_)) {
597	          fused[i] = dmin[i];
598	        }
599	      }
600	      if (dbg_pub_) {
601	        publishLike(*msg, dmin, dbg_pub_);
602	      }
603	    }
604	    publishLike(*msg, fused, scan_pub_);
605	  }
606	
607	  // Bin the cached collapsed depth onto this scan's beam grid (min per beam).
608	  // Returns false (and leaves dmin untouched) if no fresh, in-band depth.
609	  bool depthProfile(const sensor_msgs::msg::LaserScan & scan, size_t n,
610	    std::vector<float> & dmin)
611	  {
612	    if (!have_depth_) {
613	      return false;
614	    }
615	    const double age =
616	      (rclcpp::Time(scan.header.stamp) - depth_stamp_).seconds();
617	    if (std::abs(age) > max_depth_age_) {
618	      return false;
619	    }
620	    const float amin = scan.angle_min, amax = scan.angle_max;
621	    const float rmin = scan.range_min, rmax = scan.range_max;
622	    const float ainc = scan.angle_increment;
623	    std::vector<float> out(n, kInf);
624	    bool any = false;
625	    for (size_t i = 0; i < depth_brg_.size(); ++i) {
626	      const float b = depth_brg_[i];
627	      const float r = depth_rng_[i];
628	      if (b >= amin && b <= amax && r >= rmin && r <= rmax) {
629	        // np.round = round-half-to-even; std::lrint matches (default FE_TONEAREST)
630	        long idx = std::lrint((b - amin) / ainc);
631	        if (idx < 0) {
632	          idx = 0;
633	        } else if (idx > static_cast<long>(n) - 1) {
634	          idx = static_cast<long>(n) - 1;
635	        }
636	        if (r < out[idx]) {
637	          out[idx] = r;
638	        }
639	        any = true;
640	      }
641	    }
642	    if (!any) {
643	      return false;
644	    }
645	    dmin = std::move(out);
646	    return true;
647	  }
